scene.onHitWall(SpriteKind.duck, function (sprite, location) {
    sprites.destroy(sprite)
})
sprites.onOverlap(SpriteKind.Player, SpriteKind.duck, function (sprite, otherSprite) {
    if (Canstart) {
        otherSprite.destroy()
        scene.cameraShake(4, 500)
        if (Immunity) {
            music.play(music.createSoundEffect(WaveShape.Noise, 895, 2190, 255, 0, 500, SoundExpressionEffect.None, InterpolationCurve.Linear), music.PlaybackMode.InBackground)
        } else if (!(Immunity)) {
            info.changeLifeBy(-1)
            music.bigCrash.play()
        }
    }
})
