info.onLifeZero(function () {
    music.stopAllSounds()
    if (info.score() >= info.highScore()) {
        game.gameOver(true)
    } else {
        game.gameOver(false)
    }
})
sprites.onOverlap(SpriteKind.Projectile, SpriteKind.duck, function (sprite, otherSprite) {
    if (Canstart) {
        timer.background(function () {
            music.play(music.createSoundEffect(WaveShape.Noise, 5000, 917, 255, 255, 200, SoundExpressionEffect.None, InterpolationCurve.Linear), music.PlaybackMode.UntilDone)
        })
        if (_5score) {
            info.changeScoreBy(5)
        } else if (!(_5score)) {
            info.changeScoreBy(1)
        }
        otherSprite.destroy()
        sprite.startEffect(effects.fire)
    }
})
