game.onUpdateInterval(randint(15000, 40000), function () {
    if (Canstart) {
        timer.background(function () {
            music.play(music.melodyPlayable(music.magicWand), music.PlaybackMode.UntilDone)
        })
        Event = sprites.create(assets.image`Event`, SpriteKind.Event)
        if (Dungom) {
            tiles.placeOnRandomTile(Event, assets.tile`myTile3`)
        } else if (Footfiled) {
            tiles.placeOnRandomTile(Event, sprites.builtin.field1)
        } else if (Plain) {
            tiles.placeOnRandomTile(Event, sprites.castle.tileDarkGrass1)
        }
    }
})
game.onUpdateInterval(randint(20000, 40000), function () {
    if (Canstart) {
        timer.background(function () {
            music.play(music.melodyPlayable(music.magicWand), music.PlaybackMode.UntilDone)
        })
        Shield = sprites.create(assets.image`myImage5`, SpriteKind.Event)
        if (Dungom) {
            tiles.placeOnRandomTile(Shield, assets.tile`myTile3`)
        } else if (Footfiled) {
            tiles.placeOnRandomTile(Shield, sprites.builtin.field1)
        } else if (Plain) {
            tiles.placeOnRandomTile(Shield, sprites.castle.tileDarkGrass1)
        }
    }
})
